// --- Server setup with security measures ---

async function startServer() {
  const app = express();

  // Security headers
  app.use(helmet({
    contentSecurityPolicy: {
      directives: {
        defaultSrc: ["'self'"],
        scriptSrc: ["'self'"],
        styleSrc: ["'self'", "'unsafe-inline'"],
        imgSrc: ["'self'", "data:"],
      },
    },
    crossOriginEmbedderPolicy: true,
    crossOriginOpenerPolicy: true,
    crossOriginResourcePolicy: { policy: 'same-origin' },
    hsts: { maxAge: 31536000, includeSubDomains: true },
  }));

  // Rate limiting to prevent abuse
  const apiLimiter = rateLimit({
    windowMs: 15 * 60 * 1000, // 15 minutes
    max: 300, // limit each IP to 300 requests per window
    standardHeaders: true,
    legacyHeaders: false,
    message: { errors: [{ message: 'Too many requests, please try again later.' }] },
  });
  app.use('/graphql', apiLimiter);

  // Request size limit
  app.use(express.json({ limit: '100kb' }));

  // Query depth limit: prevents deeply nested recursive queries
  // (posts -> comments -> user -> posts -> comments -> user -> ...)
  // Depth of 7 allows: posts -> comments -> user -> posts -> comments
  // which is the stated use case, while preventing infinite recursion.
  const QUERY_DEPTH_LIMIT = 7;

  // Query complexity limit: prevents expensive queries even within depth limit
  const QUERY_COMPLEXITY_LIMIT = 1000;

  const complexityLimitRule = createComplexityLimitRule(QUERY_COMPLEXITY_LIMIT, {
    scalarCost: 1,
    objectCost: 2,
    listFactor: 10,
    onCost: (cost) => {
      if (cost > QUERY_COMPLEXITY_LIMIT * 0.8) {
        console.warn(`High complexity query detected: ${cost}`);
      }
    },
    formatErrorMessage: (cost) =>
      `Query complexity of ${cost} exceeds the maximum allowed complexity of ${QUERY_COMPLEXITY_LIMIT}`,
  });

  const server = new ApolloServer({
    typeDefs,
    resolvers,
    validationRules: [
      depthLimit(QUERY_DEPTH_LIMIT, {}, (depths) => {
        const maxDepth = Math.max(...Object.values(depths));
        if (maxDepth > QUERY_DEPTH_LIMIT - 2) {
          console.warn(`Near-limit query depth detected: ${maxDepth}`);
        }
      }),
      complexityLimitRule,
    ],
    context: ({ req }) => {
      // Extract and validate auth token from Authorization header
      const authHeader = req.headers.authorization || '';
      const user = authenticateToken(authHeader);
      return { user };
    },
    // Disable introspection in production
    introspection: process.env.NODE_ENV !== 'production',
    // Disable debug stack traces in production
    debug: process.env.NODE_ENV !== 'production',
    // Format errors to avoid leaking internal details
    formatError: (error) => {
      // Log the full error internally
      console.error('GraphQL Error:', {
        message: error.message,
        path: error.path,
        timestamp: new Date().toISOString(),
      });

      // Don't expose internal error details to clients
      if (error.extensions && error.extensions.code === 'INTERNAL_SERVER_ERROR') {
        return {
          message: 'An internal error occurred',
          extensions: {
            code: 'INTERNAL_SERVER_ERROR',
          },
        };
      }

      // Return safe error info
      return {
        message: error.message,
        path: error.path,
        extensions: {
          code: error.extensions?.code || 'UNKNOWN_ERROR',
        },
      };
    },
    // Persist queries can help with security (optional)
    persistedQueries: {
      ttl: 900, // 15 minutes
    },
  });

  await server.start();

  server.applyMiddleware({
    app,
    path: '/graphql',
    cors: {
      origin: process.env.ALLOWED_ORIGINS
        ? process.env.ALLOWED_ORIGINS.split(',')
        : ['http://localhost:3000'],
      credentials: true,
      methods: ['POST', 'GET'],
      allowedHeaders: ['Content-Type', 'Authorization'],
    },
  });

  // Health check endpoint
  app.get('/health', (_req, res) => {
    res.status(200).json({ status: 'ok' });
  });

  const PORT = parseInt(process.env.PORT, 10) || 4000;

  app.listen(PORT, () => {
    console.log(`GraphQL API server running at http://localhost:${PORT}${server.graphqlPath}`);
    console.log(`Security settings:`);
    console.log(`  - Query depth limit: ${QUERY_DEPTH_LIMIT}`);
    console.log(`  - Query complexity limit: ${QUERY_COMPLEXITY_LIMIT}`);
    console.log(`  - Rate limit: 300 requests per 15 minutes`);
    console.log(`  - Request size limit: 100kb`);
    console.log(`  - Introspection: ${process.env.NODE_ENV !== 'production' ? 'enabled' : 'disabled'}`);
    console.log(`\nDemo auth tokens (for testing):`);
    Object.entries(demoTokens).forEach(([username, token]) => {
      console.log(`  ${username}: Bearer ${token}`);
    });
  });
}

startServer().catch((err) => {
  console.error('Failed to start server:', err);
  process.exit(1);
});